jobEntity.trigger(["update.job_status"], async (whatWas, whatIs, job) => {
  if (whatWas.job_status === whatIs.job_status) return

  const host = await UserService.getUserById(job.host_id)
  if (!host?.email) return

  await Mail.sendOne(
    host.email,
    `Job updated - ${whatIs.job_status}`,
    buildEmail(host.firstName, job.title_name, whatIs.job_status)
  )
})

