booksEntity.trigger(["create", "update"], (_ww, _wi, book) => {
  searchIndex.upsert(book.uuid, {
    title: book.title_name,
    description: book.description
  })
})

booksEntity.trigger(["delete"], (whatWas, _wi, book) => {
  AuditLog.record({
    action: "delete",
    entity: "books",
    entityId: book.uuid,
    snapshot: whatWas
  })
})

booksEntity.intercept("delete", (req, res, next) => {
  if (!req.user?.isAdmin) {
    return res.status(403).json({ message: "Forbidden" })
  }
  next()
})

jobEntity.intercept("update.provider_id", async (req, res, next) => {
  const job = await jobService.findById(req.params.id)
  if (job?.provider_id && job.provider_id !== req.user.uuid) {
    return res.status(403).json({ message: "Cannot reassign a job you do not own" })
  }
  next()
})

profileEntity.intercept("update.personal_information", (req, res, next) => {
  // fires for PATCH /:id with body { personal_information: ... }
  // also fires for PATCH /:id/nested with body.field = "personal_information.email"
  if (req.user.uuid !== req.params.id) {
    return res.status(403).json({ message: "Cannot edit another profile" })
  }
  next()
})

booksEntity.intercept(["update.status", "update.libraryId"], async (req, res, next) => {
  // fires if status OR libraryId is being updated
  await AuditLog.record({ user: req.user.uuid, fields: Object.keys(req.body) })
  next()
})

booksEntity.intercept("read", (req, res, next) => {
