// Daily revenue over 30 days for a specific category
await entity.analyze({
  type: "timeseries",
  metric: "sum",
  field: "amount",
  interval: "day",
  filter: { category: "income" },
  window: { from: thirtyDaysAgo, to: now }
})

// Top 5 highest-paying jobs this month
await entity.analyze({ type: "top", field: "amount", limit: 5,
  filter: { job_status: "completed" }, window: { from: monthStart, to: now } })

await entity.analyze({ type: "rate", interval: "day",
  filter: { status: "active" }, window: { from: weekAgo, to: now } })
// rate: 14.5 means 14.5 documents per day on average

// Revenue change vs prior 7 days
await entity.analyze({
  type: "field_change",
  field: "amount",
  filter: { category: "income" },
  window: { from: sevenDaysAgo, to: now }
})

await entity.analyze({
  type: "funnel",
  groupBy: "job_status",
  stages: ["pending", "accepted", "in_progress", "completed"],
  filter: { provider_id: providerId },
  window: { from, to }
})

await entity.analyze({
  type: "percentile",
  field: "response_time_ms",
  filter: { status: "completed" },
  window: { from: dayAgo, to: now }
})

